command.text:

var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('hrdmctca')._controlBehavior;
var e1 = (v ? 'Trường <span class="Highlight">Giờ vào</span> phải nhỏ hơn <span class="Highlight">Giờ ra</span>.' : '<span class="Highlight">Time in</span> must be less than <span class="Highlight">time out</span>.');
var e2 = (v ? 'Trường <span class="Highlight">Chi tiết ca</span> đang cập nhật không đúng, không lưu được.' : '<span class="Highlight">Detailed Shift</span> is invalid, it can not be saved.');

var l0 = g._getColumnOrder('ma_ca_ct'), l1 = g._getColumnOrder('gio_tu'), l2 = g._getColumnOrder('gio_den'), l3 = g._getColumnOrder('hs_tu'), l4 = g._getColumnOrder('hs_den');
for (var i = 1; i <= g._rowCount; i++) {
  var c1 = g._getItemValue(i, l1), c2 = g._getItemValue(i, l2);
	var t1 = parseInt(c1.substr(0, 2)) * 60 + parseInt(c1.substr(3, 2)) + (g._getItemValue(i, l3) ? 1440 : 0), t2 = parseInt(c2.substr(0, 2)) * 60 + parseInt(c2.substr(3, 2)) + (g._getItemValue(i, l4) ? 1440 : 0);
	if (f._checked) {
    if (t1 >= t2) {
		  f._errorWarningObject = g._getItem(1, g._getColumnOrder('gio_tu'));
		  $func.hideWait(id);
		  f._checked = false;
		  $message.show(e1, String.format('var f = $find(\'{0}\');f.focus(\'hrdmctca\');f._errorWarningObject.focus()', id));
      break;
	  }
  }
  if (f._checked) {
    var c0 = g._getItemValue(i, l0);
	  for (var j = i + 1; j <= g._rowCount; j ++) {
      if (c0 == g._getItemValue(j, l0)) {
        g._errorObject = g._getItem(j, l0);
        $func.hideWait(id);   
        $message.show(e2, String.format('$find(\'{0}\').focus(\'hrdmctca\');$find(\'{1}\')._errorObject.focus()', id, g.get_id()));
        f._checked = false;
        break;
      }
    }
  }
  if (!f._checked) break;
}

script.text:

function load$DetailedShift(f) {f.add_commandEvent(on$DetailedShift$ExecuteCommand);}
function close$DetailedShift(f) {try {f.remove_commandEvent(on$DetailedShift$ExecuteCommand);} catch (ex) {}}
function on$DetailedShift$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('hrdmctca')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
